// ── Extract key fields from Jira webhook payload ──────────────
const body = $input.first().json.body ?? $input.first().json;

const issue         = body.issue ?? {};
const changelog     = body.changelog ?? { items: [] };
const fields        = issue.fields ?? {};

// Find the status transition in changelog
const statusChange = changelog.items.find(i => i.field === 'status');
const toStatus     = statusChange?.toString ?? fields?.status?.name ?? '';

// Guard: only proceed when moved TO Peer Review
const isPeerReview = toStatus.toLowerCase().includes('peer review');
if (!isPeerReview) {
  return [{ json: { skip: true, reason: 'Not a peer review transition' } }];
}

const issueKey      = issue.key;
const issueId       = issue.id;
const summary       = fields.summary ?? '';
const storyPoints   = fields.story_points ?? fields.customfield_10016 ?? fields.customfield_10028 ?? 0;
const authorId      = fields.assignee?.accountId ?? '';
const authorName    = fields.assignee?.displayName ?? 'Unknown';
const projectKey    = fields.project?.key ?? '';
const boardId       = body.boardId ?? '';

return [{
  json: {
    skip: false,
    issueKey,
    issueId,
    summary,
    storyPoints,
    authorId,
    authorName,
    projectKey,
    boardId
  }
}];

// ── Tally story points per team member ───────────────────────
const issues      = $input.first().json.issues ?? [];
const authorId    = $('Extract Issue Data').first().json.authorId;

// Build map: accountId → { displayName, email, accountId, points }
const pointsMap = {};

for (const issue of issues) {
  const f          = issue.fields ?? {};
  const assignee   = f.assignee;
  if (!assignee) continue;

  const id    = assignee.accountId;
  const name  = assignee.displayName;
  const email = assignee.emailAddress ?? '';
  const pts   = f.customfield_10016 ?? f.customfield_10028 ?? f.story_points ?? 0;

  if (!pointsMap[id]) {
    pointsMap[id] = { accountId: id, displayName: name, email, points: 0 };
  }
  pointsMap[id].points += Number(pts) || 0;
}

// ── Add team members with 0 in-progress points ─────────────
// Pull from environment variable: comma-separated list of accountId:name:email
const teamRaw = $vars.TEAM_MEMBERS ?? '';
for (const entry of teamRaw.split(',')) {
  const [id, name, email] = entry.trim().split(':');
  if (!id) continue;
  if (!pointsMap[id]) {
    pointsMap[id] = { accountId: id, displayName: name ?? id, email: email ?? '', points: 0 };
  }
}

// ── Exclude original author ───────────────────────────────
delete pointsMap[authorId];

const candidates = Object.values(pointsMap);

if (candidates.length === 0) {
  return [{ json: { error: 'No eligible reviewers found', authorId } }];
}

// ── Pick reviewer with fewest points (stable sort → first alpha wins ties) ─
candidates.sort((a, b) => a.points - b.points || a.displayName.localeCompare(b.displayName));
const reviewer = candidates[0];

return [{
  json: {
    reviewer,
    allCandidates: candidates,
    issueKey:    $('Extract Issue Data').first().json.issueKey,
    summary:     $('Extract Issue Data').first().json.summary,
    authorName:  $('Extract Issue Data').first().json.authorName
  }
}];

